import pandas as pd
from pathlib import Path

custom_path = Path(r"C:\idrive -carlo\Cloud-Drive_carloboul57@gmail.com\Cloud-Drive\Full\AMAZON_FRESH\INVOICES\2024Jan1-2026Feb1CustomTransaction.xlsx")
xl = pd.ExcelFile(custom_path)
df = pd.read_excel(xl, sheet_name=xl.sheet_names[0], header=7)

# numeric columns
for c in ['total','other','other transaction fees']:
    if c in df.columns:
        df[c] = pd.to_numeric(df[c], errors='coerce').fillna(0.0)

need = {3.68,10.07,4.42,2.81}

# find rows where total or other equals these amounts (within 0.01)

def near(series, val):
    return (series - val).abs() < 0.011

hits=[]
for val in need:
    for col in ['total','other','other transaction fees']:
        if col not in df.columns:
            continue
        sub = df[near(df[col], val) | near(df[col], -val)].copy()
        for _, r in sub.iterrows():
            hits.append((val, col, r.get('date/time'), r.get('type'), r.get('order id'), r.get('sku'), r.get('description'), float(r[col]), float(r.get('total',0))))

hits_sorted = sorted(hits, key=lambda x: (x[0], str(x[2])))
print('HITS:', len(hits_sorted))
for h in hits_sorted[:200]:
    val,col,dtv,typ,oid,sku,desc,amt,total = h
    print('target',val,'col',col,'date',dtv,'type',typ,'order',oid,'sku',sku,'amt',amt,'total',total,'desc',str(desc)[:80])
